def build_cards():
    out = []
    for i, spec in enumerate(ROW_SPECS, start=1):
        en, tr, ru, uk, lr, lu, er, eu = spec
        row = {
            "id": f"official_peaky_blinders_en_{i:02d}",
            "en": en,
            "ru": ru,
            "uk": uk,
            "literalRu": lr,
            "literalUk": lu,
            "explanationRu": er,
            "explanationUk": eu,
        }
        if tr:
            row["transcription"] = tr
        out.append(row)
    return out


if __name__ == "__main__":
    import json
    import pathlib

    root = pathlib.Path(__file__).resolve().parent.parent
    out_path = root / "app" / "flashcards" / "bundles" / "official_peaky_blinders_en.json"
    payload = {
        "pack": PACK,
        "cards": build_cards(),
    }
    out_path.write_text(
        json.dumps(payload, ensure_ascii=False, indent=2) + "\n",
        encoding="utf-8",
    )
    print("Wrote", out_path, "cards:", len(payload["cards"]))
